import type React from 'react';
import { createContextHook } from '@universe-design/react-utilities';
import type { CheckedType } from '../interface';
import type { DoublyTreeNode } from '../util';

export interface TreeNodeContextType {
  doublyTreeNode: DoublyTreeNode;
  checkboxRef: React.RefObject<HTMLInputElement>;
  expandButtonRef: React.RefObject<HTMLButtonElement>;
  isSelected: boolean | undefined;
  isChecked: CheckedType | undefined;
  isExpanded: boolean;
}

const { Provider: TreeNodeContextProvider, useContext: useTreeNodeContext } = createContextHook<TreeNodeContextType>(
  'TreeNodeContext',
  {
    strict: true,
  },
);

export { TreeNodeContextProvider, useTreeNodeContext };
